147→<script lang="ts">
148→import { Vue, Component, Prop, Watch } from 'vue-property-decorator'
149→import { Message, MessageBox } from 'element-ui'
150→import { dailyReportAiApis } from '@/apis'
151→import type { AiEmailTask } from '@/apis/StaffPage/dailyReportAiApis'
152→import PromptTestDialog from './PromptTestDialog.vue'
153→
154→@Component({ name: 'AiEmailTaskConfig', components: { PromptTestDialog } })
155→export default class AiEmailTaskConfig extends Vue {
156→    @Prop({ type: Boolean, default: false }) visible!: boolean
157→
158→    taskList: AiEmailTask[] = []
159→    selectedTask: AiEmailTask | null = null
160→    saving = false
161→    showTestDialog = false
162→
163→    form = {
164→        name: '',
165→        dimension: 'department',
166→        report_range: 'today',
167→        send_cycle: 'daily',
168→        send_day: 1,
169→        send_time: '09:00',
170→        system_prompt: '',
171→    }
172→
173→    @Watch('visible')
174→    onVisibleChange(val: boolean) {
175→        if (val) {
176→            this.selectedTask = null
177→            this.loadTasks()
178→        }
179→    }
180→
181→    async loadTasks() {
182→        this.taskList = await dailyReportAiApis.getEmailTaskList()
183→        if (this.selectedTask) {
184→            // 如果当前选中的任务还在列表中，刷新它
185→            const found = this.taskList.find(t => t.id === this.selectedTask!.id)
186→            if (found) {
187→                this.selectTask(found)
188→            } else {
189→                this.selectedTask = null
190→            }
191→        } else if (this.taskList.length) {
192→            // 没有选中任务时，自动选中第一个
193→            this.selectTask(this.taskList[0])
194→        }
195→    }
196→
197→    selectTask(task: AiEmailTask) {
198→        this.selectedTask = task
199→        this.form = {
200→            name: task.name,
201→            dimension: task.dimension,
202→            report_range: task.report_range,
203→            send_cycle: task.send_cycle,
204→            send_day: task.send_day ?? 1,
205→            send_time: task.send_time,
206→            system_prompt: task.system_prompt,
207→        }
208→    }
209→
210→    async createTask() {
211→        const id = await dailyReportAiApis.createEmailTask({
212→            name: '新任务',
213→            system_prompt: `# Role
214→你是一位拥有 10 年以上经验的高级运营总监及项目管理专家，擅长从繁杂的员工日报中抽丝剥茧，精准捕捉各部门的关键进展、潜在风险以及团队协作中的断层。
215→
216→# Task
217→我将为你提供一份公司各部门员工的日报汇总。请你作为我的"管理顾问"，按照以下框架进行深度解读，帮我识别出今天最值得关注的大事。
218→
219→# Analysis Framework
220→请按部门（如：程序组、美术组、策划组、运营组等）对日报进行解析，输出以下内容：
221→
222→核心里程碑 (Key Milestones)： 谁完成了具有阶段性意义的任务？是否有重要的功能上线或关键素材产出？
223→
224→潜在风险与阻碍 (Risks & Bottlenecks)：
225→
226→延期预警： 哪些任务停滞不前或进度明显滞后？
227→
228→协作脱节： 是否有员工提到在等待其他部门的配合？
229→
230→负面情绪： 日报中是否流露出压力过大、迷茫或消极的信号？
231→
232→异动监控 (Anomaly Detection)： 记录内容过于笼统（如"处理杂事"）或与目标计划严重不符的情况。
233→
234→管理建议 (Managerial Advice)： 针对上述问题，建议我今天找谁谈话，或者需要开会解决哪个具体痛点？
235→
236→# Output Style
237→
238→精简： 过滤掉琐碎的"日常打杂"，只汇报对全局有影响的信息。
239→
240→直观： 使用 Markdown 表格或清晰的分级标题。
241→
242→犀利： 能够读懂"字里行间"的意思（比如：当员工连续三天写"调研中"，可能代表他卡住了）。
243→
244→# Constraints
245→
246→禁止简单罗列原文，必须经过二次加工和逻辑归纳。
247→
248→如果日报中包含多部门协作的冲突，请优先标注。`,
249→            dimension: 'department',
250→            report_range: 'today',
251→            send_cycle: 'daily',
252→            send_day: 1,
253→            send_time: '09:00',
254→        })
255→        if (id) {
256→            await this.loadTasks()
257→            const created = this.taskList.find(t => t.id === id)
258→            if (created) this.selectTask(created)
259→            Message.success('创建成功')
260→        }
261→    }
262→
263→    async saveTask() {
264→        if (!this.selectedTask) return
265→        if (!this.form.name.trim()) {
266→            Message.warning('请输入任务名称')
267→            return
268→        }
269→        if (!this.form.system_prompt.trim()) {
270→            Message.warning('请输入 AI 分析 Prompt')
271→            return
272→        }
273→        this.saving = true
274→        try {
275→            await dailyReportAiApis.updateEmailTask({
276→                id: this.selectedTask.id,
277→                ...this.form,
278→            })
279→            Message.success('保存成功')
280→            await this.loadTasks()
281→        } finally {
282→            this.saving = false
283→        }
284→    }
285→
286→    async handleDelete() {
287→        if (!this.selectedTask) return
288→        try {
289→            await MessageBox.confirm('确定删除该任务？', '提示', { type: 'warning' })
290→        } catch {
291→            return
292→        }
293→        await dailyReportAiApis.deleteEmailTask(this.selectedTask.id)
294→        this.selectedTask = null
295→        Message.success('已删除')
296→        await this.loadTasks()
297→    }
298→
299→    handleTest() {
300→        if (!this.form.system_prompt.trim()) {
301→            Message.warning('请先输入 AI 分析 Prompt')
302→            return
303→        }
304→        this.showTestDialog = true
305→    }
306→
307→    async handleToggle(task: AiEmailTask, val: boolean) {
308→        await dailyReportAiApis.toggleEmailTask(task.id, val ? 1 : 0)
309→        await this.loadTasks()
310→    }
311→
312→    getCycleLabel(task: AiEmailTask): string {
313→        const dayOfWeekMap: Record<number, string> = { 1: '周一', 2: '周二', 3: '周三', 4: '周四', 5: '周五', 6: '周六', 7: '周日' }
314→        switch (task.send_cycle) {
315→            case 'daily': return '每日'
316→            case 'weekly': return `每周${dayOfWeekMap[task.send_day] || ''}`
317→            case 'monthly': return `每月${task.send_day}号`
318→            default: return task.send_cycle
319→        }
320→    }
321→}
322→</script>
