159→// ----------------------------------------------------------------
160→// 意图识别：提取查询槽位
161→// ----------------------------------------------------------------
162→
163→export interface ExtractSlotsResult {
164→    intent: 'analyze' | 'new_query'
165→    slots_complete: boolean
166→    member_type: 'group' | 'individual'
167→    members: string[]
168→    period_start: string
169→    period_end: string
170→    period_raw: string
171→    reply: string
172→    conversation_id: string
173→}
174→
175→/**
176→ * 从 AI 原始文本中解析槽位 JSON，兼容 markdown 代码块包裹
177→ */
178→function parseSlotJson(text: string): ExtractSlotsResult {
179→    const fallback: ExtractSlotsResult = {
180→        intent: 'new_query',
181→        slots_complete: false,
182→        members: [],
183→        member_type: 'individual',
184→        period_start: '',
185→        period_end: '',
186→        period_raw: '',
187→        reply: '抱歉没理解你的意思，请告诉我你想查哪个分组或具体成员的日报，以及查哪个时间段？',
188→        conversation_id: '',
189→    }
190→    const match = text.match(/\{[\s\S]*\}/)
191→    if (!match) {
192→        console.warn('[AiSlots] no JSON found in answer', text.slice(0, 500))
193→        return fallback
194→    }
195→    try {
196→        const data = JSON.parse(match[0])
197→        return {
198→            intent: data.intent ?? 'new_query',
199→            slots_complete: !!data.slots_complete,
200→            members: data.members ?? [],
201→            member_type: data.member_type ?? '',
