296→    const headers: Record<string, string> = {
297→        'Content-Type': 'application/json',
298→    }
299→    const axiosDefaults = (axiosPostWithInt as any)?.defaults?.headers?.common ?? {}
300→    Object.assign(headers, axiosDefaults)
301→
302→    // AI streaming 由 oa-core TransferRequestService 完成，通过 ai_analysis_config 参数控制
303→    const { system_prompt, history, ...restParams } = params
304→    const payload: Record<string, any> = {
305→        ...restParams,
306→        response_format: 'stream',
307→        ai_analysis_config: {
308→            system_prompt: system_prompt || '',
309→            target_field: 'query',
310→            history: history || [],
311→        },
312→    }
313→
314→    return fetch(url, {
315→        method: 'POST',
316→        headers,
317→        credentials: 'include',
318→        signal,
319→        body: JSON.stringify(handlerParams(payload)),
320→    })
321→}
