126→    /**
127→     * 测试 Prompt 效果：后端查询加密日报数据，返回 JSON，AI 分析由 oa-core TransferRequestService 完成。
128→     */
129→    public function taskTest(Request $request): JsonResponse
130→    {
131→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
132→        if (!$this->inWhitelist($sfuserId)) {
133→            return $this->responseJsonFail('无权限');
134→        }
135→
136→        $systemPrompt = $request->input('system_prompt', '');
137→        $dimension = $request->input('dimension', 'department');
138→        $reportRange = $request->input('report_range', 'today');
139→        $groupKey = $request->input('group_key', '');
140→
141→        // 计算日期范围
142→        $today = now()->toDateString();
143→        [$startDate, $endDate] = match ($reportRange) {
144→            'last_3_days' => [now()->subDays(2)->toDateString(), $today],
145→            'last_7_days' => [now()->subDays(6)->toDateString(), $today],
146→            default => [$today, $today],
147→        };
148→
149→        // 拉取该用户能看到日报的全部员工
150→        $dailyService = app(DailyReportService::class);
151→        $subordinates = $dailyService->getSubordinates($sfuserId);
152→        $groupUserIds = [];
153→        foreach ($subordinates['group_users'] as $userIds) {
154→            $groupUserIds = array_merge($groupUserIds, $userIds);
155→        }
156→        $targetUserIds = array_unique(array_merge(
157→            $subordinates['direct_subordinates'],
158→            $subordinates['depart_subordinates'],
159→            $subordinates['other_subordinates'],
160→            $subordinates['focus_users'],
161→            $groupUserIds
162→        ));
163→
164→        if (empty($targetUserIds)) {
165→            return $this->responseJsonFail('没有可查看的员工');
166→        }
167→
168→        // 拉取日报数据
169→        $data = $dailyService->getOthersDailyReportListEnable($startDate, $endDate, $sfuserId, $targetUserIds, 10000);
170→        if (empty($data) || empty($data['reports']) || empty($data['reports']['report_list'])) {
171→            return $this->responseJsonFail('所选日期范围内没有日报数据');
172→        }
173→
174→        $reportList = $data['reports']['report_list'];
175→        $reportSfuserIds = array_unique(array_column($reportList, 'sfuser_id'));
176→
177→        // 构建分组映射
178→        $sfuserGroupMap = $this->buildGroupMap($reportSfuserIds, $dimension);
179→
180→        // 按维度分组日报
181→        $grouped = [];
182→        foreach ($reportList as $report) {
183→            $uid = $report['sfuser_id'];
184→            $key = $sfuserGroupMap[$uid]['key'] ?? 'unknown';
185→            $grouped[$key]['name'] = $sfuserGroupMap[$uid]['name'] ?? '';
186→            $grouped[$key]['reports'][] = $report;
187→        }
188→
189→        // 找到用户选中的分组，找不到则取第一个
190→        $targetGroup = $grouped[$groupKey] ?? reset($grouped);
191→        if (empty($targetGroup) || empty($targetGroup['reports'])) {
192→            return $this->responseJsonFail('所选分组没有日报数据');
193→        }
194→
195→        // 构建带加密标记的内容（oa-core 负责解密）
196→        $groupNameMarked = EncryptService::app()->markEncrString($targetGroup['name']);
197→        $content = "【分组：{$groupNameMarked}】\n\n";
198→        $no = 0;
199→        foreach ($targetGroup['reports'] as $report) {
200→            $nickname = $report['data']['nickname'] ?? '';
201→            if (empty($nickname)) {
202→                continue;
203→            }
204→            $nickname = EncryptService::app()->markEncrString(e($nickname));
205→            $reportContent = EncryptService::app()->markEncrString($report['content']);
206→            ++$no;
207→            $content .= $no.'、 '.$nickname."\n".$reportContent."\n\n";
208→        }
209→
210→        if ($no === 0) {
211→            return $this->responseJsonFail('该分组没有有效的日报内容');
212→        }
213→
214→        \Log::info('[lbl][0416-AI日报][AiEmail][TEST] 开始测试 Prompt', [
215→            'sfuser_id' => $sfuserId,
216→            'dimension' => $dimension,
217→            'group_key' => $groupKey,
218→            'group_name' => $targetGroup['name'],
219→            'report_count' => $no,
220→            'content_len' => mb_strlen($content),
221→        ]);
222→
223→        // 从 MailConfig 读取 sfuser_authorized_token
224→        $mc = MailConfig::where('type', "daily_report_{$sfuserId}")->first();
225→        $sfuserToken = $mc ? Arr::get($mc->config, 'sfuser_authorized_token', '') : '';
226→        if (empty($sfuserToken)) {
227→            return $this->responseJsonFail('未配置邮件授权 Token，请先在管理后台配置邮件');
228→        }
229→
230→        // 构建摘要
231→        $dimensionLabel = $dimension === 'direct_manager' ? '按直接主管' : '按部门';
232→        $rangeLabel = match ($reportRange) {
233→            'last_3_days' => '近3天',
234→            'last_7_days' => '近7天',
235→            default => '今日',
236→        };
237→        $dateRange = $startDate === $endDate ? $startDate : "{$startDate} ~ {$endDate}";
238→
239→        // 返回数据 + decrypt_config + ai_analysis_config，由 oa-core TransferRequestService 做解密+AI streaming
240→        return $this->responseJsonSuccess([
241→            'content' => $content,
242→            'summary' => "{$dimensionLabel} · {$rangeLabel}（{$dateRange}）· {$no}份日报",
243→            'decrypt_config' => [
244→                'obj' => '$this',
245→                'decrypt_columns' => [],
246→                'partly_decrypt_columns' => ['content'],
247→                'tokens' => [$sfuserToken],
248→                'operation' => 'send_email',
249→            ],
250→            'ai_analysis_config' => [
251→                'system_prompt' => $systemPrompt,
252→                'target_field' => 'content',
253→                'compress' => true,
254→            ],
255→        ]);
256→    }
257→
258→    /**
259→     * 根据维度构建 sfuser_id => ['key' => 分组键, 'name' => 分组名] 的映射.
260→     * 复用 DailyReportAiEmailJob 中的分组逻辑.
261→     */
262→    private function buildGroupMap(array $sfuserIds, string $dimension): array
263→    {
264→        if (empty($sfuserIds)) {
265→            return [];
266→        }
267→
268→        $map = [];
269→
270→        if ($dimension === 'direct_manager') {
271→            $users = Sfuser::whereIn('id', $sfuserIds)
272→                ->select('id', 'direct_supervisor_id', 'direct_supervisor_nickname')
273→                ->get();
274→            foreach ($users as $user) {
275→                $managerId = $user->direct_supervisor_id ?: 0;
276→                $managerName = $user->direct_supervisor_nickname ?: '无直接主管';
277→                $map[$user->id] = [
278→                    'key' => "mgr_{$managerId}",
279→                    'name' => $managerName,
280→                ];
281→            }
282→        } else {
283→            $users = Sfuser::whereIn('id', $sfuserIds)
284→                ->select('id', 'department_id')
285→                ->get();
286→            $deptIds = $users->pluck('department_id')->filter()->unique()->values()->toArray();
287→            $deptNames = [];
288→            if (!empty($deptIds)) {
289→                $deptNames = DB::table('job_departments')
290→                    ->whereIn('department_id', $deptIds)
291→                    ->pluck('department_name', 'department_id')
292→                    ->toArray();
293→            }
294→            foreach ($users as $user) {
295→                $deptId = $user->department_id ?: 0;
296→                $deptName = $deptNames[$deptId] ?? '未分配部门';
297→                $map[$user->id] = [
298→                    'key' => "dept_{$deptId}",
299→                    'name' => $deptName,
300→                ];
301→            }
302→        }
303→
304→        return $map;
305→    }
306→
307→    private function inWhitelist(int $sfuserId): bool
308→    {
309→        // 复用 DailyReportAiController 相同的白名单逻辑，从 oa_settings 表动态读取
310→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
311→        if (!$setting || !$setting->is_on) {
312→            return false;
313→        }
314→        return in_array($sfuserId, $setting->ids ?? []);
315→    }
316→}
