 43→<script lang="ts">
 44→import MarkdownIt from 'markdown-it'
 45→import { Vue, Component, Prop, Watch } from 'vue-property-decorator'
 46→import { dailyReportAiApis } from '@/apis'
 47→
 48→const md = new MarkdownIt({ html: true, breaks: true, linkify: true })
 49→
 50→@Component({ name: 'PromptTestDialog' })
 51→export default class PromptTestDialog extends Vue {
 52→    @Prop({ default: false }) visible!: boolean
 53→    @Prop({ default: '' }) systemPrompt!: string
 54→    @Prop({ default: 'department' }) dimension!: string
 55→    @Prop({ default: 'today' }) reportRange!: string
 56→
 57→    step: 'loading' | 'streaming' | 'done' | 'error' = 'loading'
 58→    errorMsg = ''
 59→    rawContent = ''
 60→    summaryLabel = ''
 61→    private streamAbort: AbortController | null = null
 62→
 63→    get renderedContent(): string {
 64→        return md.render(this.rawContent || '')
 65→    }
 66→
 67→    @Watch('visible')
 68→    onVisibleChange(val: boolean) {
 69→        if (val) {
 70→            this.runTest()
 71→        }
 72→    }
 73→
 74→    private async runTest() {
 75→        this.step = 'loading'
 76→        this.rawContent = ''
 77→        this.errorMsg = ''
 78→        this.summaryLabel = ''
 79→
 80→        try {
 81→            this.streamAbort = new AbortController()
 82→
 83→            // 直接调后端，group_key 传空串，后端自动取第一个分组
 84→            const response = await dailyReportAiApis.testEmailTask({
 85→                system_prompt: this.systemPrompt,
 86→                dimension: this.dimension,
 87→                report_range: this.reportRange,
 88→                group_key: '_first_',
 89→            }, this.streamAbort.signal)
 90→
 91→            const reader = response.body!.getReader()
 92→            const decoder = new TextDecoder()
 93→            let buffer = ''
 94→
 95→            while (true) {
 96→                const { done, value } = await reader.read()
 97→                if (done) break
 98→                buffer += decoder.decode(value, { stream: true })
 99→                const lines = buffer.split('\n')
100→                buffer = lines.pop() ?? ''
101→
102→                for (const line of lines) {
103→                    if (!line.startsWith('data: ')) continue
104→                    try {
105→                        const parsed = JSON.parse(line.slice(6))
106→                        if (parsed.error_code !== 0) {
107→                            this.errorMsg = parsed.error_msg || '服务端返回错误'
108→                            this.step = 'error'
109→                            return
110→                        }
111→                        const data = parsed.data
112→                        // TransferRequestService SSE 格式：meta（首帧，含 summary）+ chat（流式内容，is_finished 标记结束）
113→                        if (data.type === 'meta') {
114→                            this.summaryLabel = data.summary || ''
115→                            this.step = 'streaming'
116→                        } else if (data.type === 'chat') {
117→                            if (data.content) {
118→                                if (this.step === 'loading') this.step = 'streaming'
119→                                this.rawContent += data.content
120→                                this.$nextTick(() => this.scrollToBottom())
121→                            }
122→                            // is_finished=true 表示 AI 流结束
123→                            if (data.is_finished) {
124→                                if (!this.rawContent) {
125→                                    this.errorMsg = 'AI 分析未返回结果，可能是服务暂时不可用，请稍后重试'
126→                                    this.step = 'error'
127→                                    return
128→                                }
129→                                this.step = 'done'
130→                            }
131→                        }
132→                    } catch {}
133→                }
134→            }
135→
136→            if (this.step === 'streaming') this.step = 'done'
137→        } catch (e: any) {
138→            if (e?.name !== 'AbortError') {
139→                this.errorMsg = e?.message || '测试失败'
140→                this.step = 'error'
141→            }
142→        } finally {
143→            this.streamAbort = null
144→        }
145→    }
146→
147→    private scrollToBottom() {
148→        const el = this.$refs.resultBody as HTMLElement
149→        if (el) el.scrollTop = el.scrollHeight
150→    }
151→
152→    private handleStop() {
153→        this.streamAbort?.abort()
154→        this.step = 'done'
155→    }
156→
157→    private handleClose() {
158→        this.streamAbort?.abort()
159→        this.$emit('update:visible', false)
160→    }
161→}
